,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Prototyp - Collections erzeugen'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- +-------------+',
'-- | Collections |',
'-- +-------------+',
'',
'-- ----------------',
'-- Vertriebslcuster',
'-- ',
'-- N001 : ID',
'-- C001 : Name',
'-- C002 : Technologie',
'-- C003 : Ausbaustatus',
'-- D001 : Plantermin',
'-- D002 : VVM_von',
'-- D003 : VVM_bis ',
'-- ----------------',
'APEX_COLLECTION.CREATE_OR_TRUNCATE_COLLECTION(',
'    p_collection_name => ''VERTRIEBSCLUSTER'');',
'',
'-- Testdaten',
'APEX_COLLECTION.ADD_MEMBER(',
'        p_collection_name => ''VERTRIEBSCLUSTER'',',
'        p_c001            => ''VC 1'',',
'        p_c002            => ''FTTH'',',
'        p_c003            => ''NotPlanned'',',
'        p_n001            => 1,',
'        p_d001            => NULL, ',
'        p_d002            => NULL, ',
'        p_d003            => NULL ',
'        );',
'APEX_COLLECTION.ADD_MEMBER(',
'        p_collection_name => ''VERTRIEBSCLUSTER'',',
'        p_c001            => ''VC 2'',',
'        p_c002            => ''FTTH'',',
'        p_c003            => ''AreaPlanned'',',
'        p_n001            => 2,',
'        p_d001            => NULL, ',
'        p_d002            => NULL, ',
'        p_d003            => NULL ',
'        );',
'APEX_COLLECTION.ADD_MEMBER(',
'        p_collection_name => ''VERTRIEBSCLUSTER'',',
'        p_c001            => ''VC 3'',',
'        p_c002            => ''FTTH'',',
'        p_c003            => ''PreMarketing'',',
'        p_n001            => 3,',
'        p_d001            => sysdate, ',
'        p_d002            => sysdate + 30, ',
'        p_d003            => sysdate + 60 ',
'        );',
'APEX_COLLECTION.ADD_MEMBER(',
'        p_collection_name => ''VERTRIEBSCLUSTER'',',
'        p_c001            => ''VC 4'',',
'        p_c002            => ''FTTH'',',
'        p_c003            => ''underConstruction'',',
'        p_n001            => 4,',
'        p_d001            => NULL, ',
'        p_d002            => NULL, ',
'        p_d003            => NULL ',
'        );',
'-- ------------------------',
'-- Vertriebslcuster Details',
'--',
'-- N001 : VC_ID',
'-- N002 : HAUS_LFD_NR',
'-- ------------------------',
'APEX_COLLECTION.CREATE_OR_TRUNCATE_COLLECTION(',
'    p_collection_name => ''VERTRIEBSCLUSTER_DETAILS'');'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_required_patch=>wwv_flow_imp.id(214649311448422564)
