,p_parent_plug_id=>wwv_flow_imp.id(56491706319073158)
,p_region_css_classes=>'scrollbar-on-top'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--noBorders'
,p_plug_template=>wwv_flow_imp.id(213406791229554768)
,p_plug_display_sequence=>10
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT vc.versions_endtime',
unistr('       , CASE WHEN vh.operation = ''U'' THEN ''Ge\00E4ndert'' WHEN vh.operation = ''I'' THEN ''Eingef\00FCgt'' WHEN vh.operation = ''D'' THEN ''Gel\00F6scht'' END operation'),
'       , vco_lfd_nr',
'       , vermarktungscluster_objekt.vc_lfd_nr',
'       , vermarktungscluster_objekt.haus_lfd_nr',
'       , p.plz_plz plz ',
'       , p.plz_oname ort',
'       , s.str_name46 str ',
'       , h.haus_hnr hnr ',
'       , h.haus_hnr_zus hnr_zus',
'       -- 03-04-2025 -  @ticket FTTH-5143 - Anpassung Adresstruktur komplett',
'       , va.hnr_kompl  hnr_kompl',
'       , va.gebaeudeteil_name gebaeudeteil_name',
'       , h.haus_we_ges we_ges',
'       , vc.bezeichnung vermarktungscluster',
'       , vc.wholebuy wholebuy_partner',
'       , vc.inserted ',
'       , vc.updated',
'       , vc.mandant ',
'       , vh.aktueller_status',
'       , vh.vorheriger_status',
'       , vh.status_aenderungsdatum',
'       , vh.aktueller_ausbau_plan_termin',
'       , vh.vorheriger_ausbau_plan_termin',
'       , vh.ausbau_plan_termin_aenderungsdatum',
'       , TO_CHAR(vh.aenderungsdatum, ''DD.MM.YYYY HH24:MI:SS'') as aenderungsdatum',
'       , CASE WHEN (vh.status_aenderungsdatum IS NOT NULL AND vh.status_aenderungsdatum >= SYSDATE - :P13_ZEITSPANNE) THEN ''S_EDIT'' END status_markierung',
'       , CASE WHEN (ausbau_plan_termin_aenderungsdatum IS NOT NULL AND vh.ausbau_plan_termin_aenderungsdatum >= SYSDATE - :P13_ZEITSPANNE) THEN ''PT_EDIT'' END plantermin_markierung',
'       , CASE WHEN (vh.aenderungsdatum IS NOT NULL AND vh.aenderungsdatum >= SYSDATE - :P13_ZEITSPANNE) THEN ''D_EDIT'' END operation_markierung',
unistr('       , CASE WHEN vh.loeschgrund = 1 THEN ''Projekt fertiggestellt'' WHEN vh.loeschgrund = 2 THEN ''Projekt zur\00FCckgezogen'' WHEN vh.loeschgrund = 3 THEN ''Test'' END loeschgrund'),
'FROM vermarktungscluster VERSIONS BETWEEN SCN MINVALUE AND MAXVALUE vc',
'     left JOIN vermarktungscluster_objekt VERSIONS BETWEEN SCN MINVALUE AND MAXVALUE ON vermarktungscluster_objekt.vco_lfd_nr = vc.vc_lfd_nr',
'     left join strav.haus h on h.haus_lfd_nr = vermarktungscluster_objekt.haus_lfd_nr',
'     left JOIN v_adressen va ON va.haus_lfd_nr = h.haus_lfd_nr',
'     left JOIN strav.stra_db s ON s.str_lfd_nr = h.str_lfd_nr',
'     left JOIN strav.plz_da p ON p.plz_plz = s.str_plz AND p.plz_alort = s.str_alort',
'     JOIN vc_hist vh ON vh.vc_lfd_nr = vc.vc_lfd_nr'))
,p_plug_source_type=>'NATIVE_IG'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
